var person = {
  "name": "John",
  "age": 25,
  "country": "USA"
};
for (var key in person) {
  console.log(key + ': ' + person[key]);
}  // name: John, age: 25, country: USA

var person = {
  "name": "John",
  "age": 25,
  "country": "USA",
  "introduce": function() {
    return 'Hello, my name is ' + this.name + '. I am ' + this.age + ' years old and I live in ' + this.country + '.';
  }
};
console.log(person.introduce());  // Hello, my name is John. I am 25 years old and I live in USA.

questions.question:
次のような構造を持つネストされたオブジェクトを作成してください。

var person = {
  "name": "John",
  "age": 25,
  "address": {
    "street": "123 Main St",
    "city": "New York",
    "country": "USA"
  }
}

作成したオブジェクトの"address"プロパティの"city"をconsole.logで表示してください。

questions.answer:
var person = {
  "name": "John",
  "age": 25,
  "address": {
    "street": "123 Main St",
    "city": "New York",
    "country": "USA"
  }
};
console.log(person.address.city);  // New York

var person = {
  "name": "John",
  "age": 25,
  "country": "USA"
};
delete person.country;
console.log(person.country);  // undefined

questions.question:
次のオブジェクトが与えられたとします：

var person = {
  "name": "John",
  "age": 25
}

このオブジェクトの"age"プロパティを26に変更してください。その後、変更後の"age"プロパティの値をconsole.logで表示してください。

次のオブジェクトが与えられたとします：

var person = {
  "name": "John",
  "age": 25,
  "greet": function() {
    return "Hello, my name is " + this.name;
  }
}

このオブジェクトの"greet"メソッドを呼び出し、その結果をconsole.logで表示してください。

questions.answer:
