questions.question:
次のようなオブジェクトがあります:

var person = {
  "name": "John",
  "age": 25
}

このpersonオブジェクトに、自身の名前をconsole.logで表示するメソッド"introduce"を追加してください。そしてそのメソッドを呼び出してください。

questions.answer:
var person = {
  "name": "John",
  "age": 25,
  "introduce": function() {
    console.log("My name is " + this.name);
  }
};
person.introduce();  // My name is John

function Person(name, age) {
  this.name = name;
  this.age = age;
}

var alice = new Person("Alice", 20);
console.log(alice);  // Person {"name": "Alice","age": 20}

function Person(name, age) {
  this.name = name;
  this.age = age;
  this.introduce = function() {
    console.log("My name is " + this.name);
  }
}

var alice = new Person("Alice", 20);
alice.introduce();  // My name is Alice

function Person(name, age) {
  this.name = name;
  this.age = age;
  this.introduce = function() {
    console.log("My name is " + this.name);
  }
}

Person.prototype.greet = function() {
  console.log("Hello! I am " + this.name + ".");
}

var alice = new Person("Alice", 20);
alice.greet();  // Hello! I am Alice.
